\Marks{1}

\end{subparts}

\item Find the total time, in minutes, that Jason stopped between Town A and Town D.

\AnswerLine[][min]
\Marks{1}

\item Calculate Jason's overall average speed, in kilometres per hour, from Town A to Town D.

\AnswerLine[][km/h]
\Marks{3}

